import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;

import java.io.IOException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    @Test
    public void testFormat_withValues() {
        CSVFormat format = CSVFormat.DEFAULT;

        String result = format.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormat_withNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");

        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        CSVFormat format = CSVFormat.DEFAULT;

        String result = format.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_withQuoteModeAllNonNull() {
        CSVFormat format = CSVFormat.DEFAULT.withQuoteMode(QuoteMode.ALL_NON_NULL);

        String result = format.format("a", "b", "c");
        assertEquals("\"a\",\"b\",\"c\"", result);
    }

    @Test
    public void testFormat_withExceptionThrown() throws Exception {
        CSVFormat format = spy(CSVFormat.DEFAULT);

        // Use reflection to get CSVFormat.format method
        Method formatMethod = CSVFormat.class.getDeclaredMethod("format", Object[].class);

        // Mock CSVPrinter constructor to throw IOException when created with StringWriter and this CSVFormat
        // Since CSVPrinter is created inside format method, we cannot mock it easily here.
        // Instead, we create a subclass of CSVFormat that overrides printRecord to throw IOException

        CSVFormat formatWithIOException = new CSVFormat(format.getDelimiter(),
                format.getQuoteCharacter(),
                format.getQuoteMode(),
                format.getCommentMarker(),
                format.getEscapeCharacter(),
                format.getIgnoreSurroundingSpaces(),
                format.getIgnoreEmptyLines(),
                format.getRecordSeparator(),
                format.getNullString(),
                format.getHeaderComments(),
                format.getHeader(),
                format.getSkipHeaderRecord(),
                format.getAllowMissingColumnNames(),
                format.getIgnoreHeaderCase(),
                format.getTrim(),
                format.getTrailingDelimiter(),
                format.getAutoFlush()) {
            @Override
            public CSVPrinter print(Appendable out) throws IOException {
                throw new IOException("Forced IOException");
            }
        };

        // Because CSVPrinter is created inside format method, and format method calls printRecord on it,
        // we cannot throw IOException directly from printRecord, but from print() we can simulate.

        // Instead of calling format, we test the exception by reflection invoking format with this subclass

        Executable executable = () -> formatWithIOException.format("a", "b");

        IllegalStateException thrown = assertThrows(IllegalStateException.class, executable);
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("Forced IOException", thrown.getCause().getMessage());
    }
}
